package com.library.model;

import lombok.AllArgsConstructor;
import lombok.Builder;
import lombok.Data;
import lombok.NoArgsConstructor;
import org.springframework.data.annotation.Id;
import org.springframework.data.mongodb.core.index.Indexed;
import org.springframework.data.mongodb.core.mapping.Document;
import org.springframework.data.mongodb.core.mapping.Field;

import java.time.LocalDateTime;

/**
 * MongoDB document representing a library member (patron).
 * membershipId is auto-generated in the format "LIB-XXXXXX".
 */
@Data
@Builder
@NoArgsConstructor
@AllArgsConstructor
@Document(collection = "members")
public class Member {

    @Id
    private String id;

    @Field("name")
    private String name;

    @Indexed(unique = true)
    @Field("email")
    private String email;

    @Field("phone")
    private String phone;

    /**
     * Auto-generated unique membership ID, e.g. "LIB-482910".
     * Generated by MemberService before persisting.
     */
    @Indexed(unique = true)
    @Field("membershipId")
    private String membershipId;

    /** BASIC or PREMIUM */
    @Field("membershipType")
    private String membershipType;

    /** Soft-delete flag; deactivating instead of deleting preserves transaction history */
    @Field("isActive")
    private boolean isActive;

    @Field("joinedAt")
    private LocalDateTime joinedAt;
}
